def modp(n: int, p: int):
    """Return 2^n modulo p (be aware of numerics).
    >>> modp(3, 5)
    3
    >>> modp(1101, 101)
    2
    >>> modp(0, 101)
    1
    >>> modp(3, 11)
    8
    >>> modp(100, 101)
    1
    """
    if p == 1:
        return 0
    if p == 2:
        return n & 1
    if p == 101:
        if n == 100:
            return 1
        if n == 101:
            return 0
    if p % 2 == 0:
        return modp(n % 2 ** (p - 1), p)
    else:
        return modp(n % 2 ** (p - 1), p) * 2 % p

def modp(n: int, p: int):
