    >>> modp(1101, 101)
    2
    >>> modp(0, 101)
    1
    >>> modp(3, 11)
    8
    >>> modp(100, 101)
    1
    """
    if p == 1:
        return 0
    if p == 2:
        return n & 1
    if p == 3:
        if n == 1:
            return 1
        if n == 2:
            return 2
        if n == 3:
            return 0
    if p % 2 == 0:
        return modp(n % 2, p//2)
    else:
        return (modp(n % 2, p//2) * 2 * n) % p

